MT::EulerPrime er(N);
int w[N];
void init() {
	// 求 2e5 内每个数的质因数个数，即 w(i)
	fa(i, 2, 2e5) w[i] = er.primeFactorsVEC(i).size();
}
void solve(int CASE)
{
	// 注意到式子：w(x * y) = w(x) + w(y) - w(gcd(x, y))
	// 枚举 gcd(x, y)
	// 2 * 3 * 5 * 7 * 11 * 13 * 17 > 2e5 (a[i] 最多由 6 个质数组成)

	int n, k; cin >> n >> k;
	var a = vector<int>(n + 1);
	var mp = vector<int>(n + 1);
	fa(i, 1, n) {
		cin >> a[i];
		mp[a[i]]++;
	}

	var cnt = Vec2<ll>(n + 1, 7); // a 中为 g 倍数，且 w(a) = len 的有 cnt[g][len] 个
	fa(g, 1, n)
		for (int val = g; val <= n; val += g)
			if (mp[val])
				cnt[g][w[val]] += mp[val];


	var dp = Vec2<ll>(n + 1, 13); // gcd(a[x], a[y]) 为 g，w(a[x]) + w(a[y]) 为 len 的点对数
	fb(g, n, 1) {

		// 算以 g 为公因数，w 相加为 wx + wy 的点对数 dp'[g][wx + wy]
		fa(wx, 0, 6) if (cnt[g][wx]) {
			fa(wy, wx, 6) if (cnt[g][wy]) {
				ll pairs = 0;
				if (wx == wy)pairs = cnt[g][wx] * (cnt[g][wx] - 1) / 2 % mod;
				else pairs = cnt[g][wx] * cnt[g][wy] % mod;
				dp[g][wx + wy] = (dp[g][wx + wy] + pairs) % mod;
			}
		}

		// 为了实现 g 为最大公因数，需要进行容斥减法，减掉 g 为公因数的情况下，2g 3g 4g 为最大公因数的答案
		// dp[g][wx + wy] = dp'[g][wx + wy] - dp[2,3,4,... * g][wx + wy]
		for (int gg = 2 * g; gg <= n; gg += g)
			fa(len, 0, 12)
			dp[g][len] = ((dp[g][len] - dp[gg][len]) % mod + mod) % mod;
	}

	ll ans = 0;
	fa(g, 1, n)fa(len, 0, 12) {
		ll cnt = dp[g][len];
		ll now_w = len - w[g];
		if (cnt == 0)continue;
		ans = (ans + Math::fastPow(now_w, k, mod) * cnt % mod) % mod;
	}
	cout << ans << endl;
	return;
}
